class Solution:
    def categorizeBox(self, length, width, height, mass):
        dims = [length, width, height]
        bulky = False
        for d in dims:
            if d >= 10000:
                bulky = True
        volume = 1
        for d in dims:
            volume *= d
        if volume >= 1000000000:
            bulky = True
        heavy = mass >= 100
        labels = {
            (True, True): 'Both',
            (True, False): 'Bulky',
            (False, True): 'Heavy',
            (False, False): 'Neither',
        }
        return labels[(bulky, heavy)]

